CREATE OR REPLACE FUNCTION fpb_get_bank_no_loan_by_memno (as_memno char) RETURNS SC_MEM_M_MEMBER_BANK_ACCNO.BANK_ACC_NO%TYPE AS $body$
DECLARE

  ls_bank_accno sc_mem_m_member_bank_accno.bank_acc_no%type;
  ls_bank_id sc_mem_m_member_bank_accno.bank_id%type;

BEGIN
  select bank_acc_no ,bank_id into STRICT ls_bank_accno ,ls_bank_id
  from sc_mem_m_member_bank_accno
  where membership_no = as_memno
  and   paid_loan = '1'
;
  if coalesce(ls_bank_accno::text, '') = '' or ls_bank_accno = 'CNV' then ls_bank_accno := ' ';end if;
  if coalesce(ls_bank_id::text, '') = '' or ls_bank_id = 'CNV' then ls_bank_id := ' ';end if;
  return trim(both ls_bank_id)||' - ' ||trim(both ls_bank_accno);
exception
when too_many_rows then return '';
when no_data_found then return '';
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
